theorem cumCP_telescope {ι : Type*}
    (E : ι → ℝ) (g : ℕ → ι) (T : ℕ) :
    cumCP E g T = E (g 0) - E (g T)

theorem finite_audit_goodhart {ι : Type*} {F : Set ι} {Ehat E : ι → ℝ} {Δ : ℝ}
    (hUD : UniformDev F Ehat E Δ) {g : ℕ → ι} (hg : Admissible g F) (T : ℕ) :
    cumCP Ehat g T ≤ cumCP E g T + 2 * Δ

